        /// <summary>
        /// Uploads a single file (avatar or document) to the wwwroot/uploads directory.
        /// </summary>
        /// <param name="file">The file to upload.</param>
        /// <returns>An object containing the relative path to the uploaded file.</returns>
        [HttpPost]
        public async Task<IActionResult> UploadFile(IFormFile file)
        {
            if (file == null || file.Length == 0)
            {
                return BadRequest("No file uploaded.");
            }

            if (file.Length > _maxFileSize)
            {
                return BadRequest($"File size exceeds the limit of {_maxFileSize / (1024 * 1024)} MB.");
            }

            var fileExtension = Path.GetExtension(file.FileName).ToLowerInvariant();
            if (!_allowedExtensions.Contains(fileExtension))
